css:
* {
  box-sizing: border-box !important;
}

html, body {
  min-height: 100vh !important;
  background: #0d1a12 !important;
  color: #c8dcc8 !important;
  font-family: 'Segoe UI', system-ui, -apple-system, sans-serif !important;
}

body::before {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  background: 
    radial-gradient(circle at 10% 20%, rgba(30,70,40,0.4) 0%, transparent 50%),
    radial-gradient(circle at 90% 80%, rgba(20,60,30,0.3) 0%, transparent 50%),
    radial-gradient(circle at 50% 50%, rgba(10,30,15,0.6) 0%, rgba(5,15,8,0.9) 100%);
  animation: bgShift 30s ease-in-out infinite alternate !important;
}

@keyframes bgShift {
  0% { background-position: 0% 0%; }
  100% { background-position: 100% 100%; }
}

.p-pageWrapper,
.p-body,
.p-body-inner,
.p-body-main,
.p-body-content,
.p-body-pageContent,
.p-body-header,
.pageContent,
.p-body-inner {
  background: transparent !important;
}

.p-body-inner {
  background: rgba(20, 40, 25, 0.85) !important;
  backdrop-filter: blur(16px) !important;
  -webkit-backdrop-filter: blur(16px) !important;
  border-radius: 40px !important;
  padding: 24px !important;
  box-shadow: 0 8px 48px rgba(0, 0, 0, 0.6), inset 0 1px 0 rgba(60,120,60,0.15) !important;
  border: 1px solid rgba(60,120,60,0.2) !important;
  margin: 16px auto !important;
}

.p-header {
  background: rgba(20, 40, 25, 0.7) !important;
  backdrop-filter: blur(12px) !important;
  border-bottom: 1px solid rgba(60,120,60,0.15) !important;
  border-radius: 40px 40px 0 0 !important;
  padding: 12px 24px !important;
}

.p-header-logo a {
  color: #a0d8a0 !important;
  font-weight: 700 !important;
  letter-spacing: -0.5px !important;
}

.p-header-logo a:hover {
  text-shadow: 0 0 40px rgba(80,200,80,0.2) !important;
}

.p-nav {
  background: rgba(20, 40, 25, 0.6) !important;
  backdrop-filter: blur(12px) !important;
  border-bottom: 1px solid rgba(60,120,60,0.15) !important;
  box-shadow: 0 4px 32px rgba(0,0,0,0.4) !important;
  padding: 0 16px !important;
}

.p-nav-inner {
  background: transparent !important;
}

.p-nav-list {
  display: flex !important;
  gap: 4px !important;
  background: transparent !important;
}

.p-nav-list .p-navEl {
  color: #b0d0b0 !important;
  font-weight: 500 !important;
  padding: 12px 20px !important;
  border-radius: 40px !important;
  transition: all 0.25s ease !important;
  background: transparent !important;
}

.p-nav-list .p-navEl:hover {
  background: rgba(60, 140, 60, 0.2) !important;
  color: #e0f0e0 !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 8px 24px rgba(0,0,0,0.3) !important;
}

.p-nav-list .p-navEl.is-selected {
  background: rgba(60, 140, 60, 0.25) !important;
  color: #d0f0d0 !important;
  box-shadow: inset 0 0 0 1px rgba(60,160,60,0.2), 0 4px 20px rgba(0,0,0,0.3) !important;
}

.p-nav-opposite {
  background: transparent !important;
}

.p-navgroup {
  background: transparent !important;
}

.p-navgroup-link {
  color: #b0d0b0 !important;
  transition: all 0.2s !important;
}

.p-navgroup-link:hover {
  color: #e0f0e0 !important;
  background: rgba(60, 140, 60, 0.15) !important;
  border-radius: 40px !important;
}

.block {
  background: rgba(30, 60, 40, 0.4) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  border-radius: 32px !important;
  border: 1px solid rgba(60,120,60,0.15) !important;
  box-shadow: 0 4px 24px rgba(0,0,0,0.3) !important;
  padding: 20px !important;
  margin-bottom: 24px !important;
  transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94) !important;
}

.block:hover {
  box-shadow: 0 8px 40px rgba(0,0,0,0.5) !important;
  transform: translateY(-2px) !important;
}

.block-container {
  background: transparent !important;
  border: none !important;
}

.block-body {
  background: transparent !important;
}

.block-minorHeader {
  color: #c0e0c0 !important;
  font-weight: 600 !important;
  padding: 12px 16px !important;
  border-bottom: 1px solid rgba(60,120,60,0.1) !important;
}

.node {
  background: rgba(25, 50, 30, 0.5) !important;
  border-radius: 24px !important;
  border: 1px solid rgba(60,120,60,0.12) !important;
  padding: 16px 20px !important;
  margin-bottom: 8px !important;
  transition: all 0.3s ease !important;
}

.node:hover {
  background: rgba(40, 80, 50, 0.6) !important;
  border-color: rgba(60,160,60,0.2) !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 8px 32px rgba(0,0,0,0.3) !important;
}

.node-title a {
  color: #c0e0c0 !important;
  font-weight: 600 !important;
}

.node-title a:hover {
  color: #e0f8e0 !important;
  text-shadow: 0 0 20px rgba(80,200,80,0.15) !important;
}

.node-stats {
  color: #90b090 !important;
}

.node-extra {
  color: #90b090 !important;
}

.node-extra-title {
  color: #a0c0a0 !important;
}

.node-extra-title:hover {
  color: #c0e0c0 !important;
}

.uix_newIndicator {
  background: rgba(60, 140, 60, 0.2) !important;
  color: #80d080 !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
}

.node-body {
  background: transparent !important;
  display: flex !important;
  align-items: center !important;
  flex-wrap: wrap !important;
  gap: 8px !important;
}

.structItem {
  background: rgba(25, 50, 30, 0.4) !important;
  border-radius: 24px !important;
  border: 1px solid rgba(60,120,60,0.1) !important;
  padding: 12px 16px !important;
  margin-bottom: 6px !important;
  transition: all 0.25s ease !important;
}

.structItem:hover {
  background: rgba(40, 80, 50, 0.5) !important;
  border-color: rgba(60,160,60,0.15) !important;
  transform: translateX(4px) !important;
}

.structItem-title {
  color: #c0e0c0 !important;
  font-weight: 500 !important;
}

.structItem-title a {
  color: #c0e0c0 !important;
}

.structItem-title a:hover {
  color: #e0f8e0 !important;
  text-shadow: 0 0 20px rgba(80,200,80,0.12) !important;
}

.structItem-statuses {
  color: #90b090 !important;
}

.structItem-status--locked {
  color: #cc8888 !important;
}

.structItem-status--sticky {
  color: #d0b080 !important;
}

.structItem-minor {
  color: #80a080 !important;
}

.structItem-minor a {
  color: #90b090 !important;
}

.structItem-minor a:hover {
  color: #b0d0b0 !important;
}

.structItem-cell--meta {
  color: #90b090 !important;
}

.structItem-latestDate {
  color: #90b090 !important;
}

.structItem--quickCreate {
  background: rgba(30, 60, 40, 0.3) !important;
  border: 1px dashed rgba(60, 120, 60, 0.2) !important;
  border-radius: 24px !important;
}

.structItem--quickCreate textarea {
  background: rgba(20, 40, 25, 0.5) !important;
  border: 1px solid rgba(60, 120, 60, 0.15) !important;
  color: #c8dcc8 !important;
  border-radius: 20px !important;
  padding: 12px !important;
}

.structItem--quickCreate textarea:focus {
  border-color: rgba(60, 160, 60, 0.4) !important;
  box-shadow: 0 0 0 4px rgba(60, 160, 60, 0.1) !important;
}

.message {
  background: rgba(30, 60, 40, 0.45) !important;
  backdrop-filter: blur(6px) !important;
  border-radius: 28px !important;
  border: 1px solid rgba(60,120,60,0.12) !important;
  padding: 0 !important;
  margin-bottom: 20px !important;
  transition: all 0.3s ease !important;
  overflow: hidden !important;
}

.message:hover {
  background: rgba(40, 80, 50, 0.55) !important;
  border-color: rgba(60,160,60,0.2) !important;
  box-shadow: 0 8px 32px rgba(0,0,0,0.4) !important;
  transform: translateY(-2px) !important;
}

.message-inner {
  background: transparent !important;
  display: flex !important;
  flex-wrap: wrap !important;
}

.message-cell {
  background: transparent !important;
  padding: 16px !important;
}

.message-cell--user {
  background: rgba(20, 40, 25, 0.3) !important;
  border-right: 1px solid rgba(60,120,60,0.1) !important;
  border-radius: 28px 0 0 28px !important;
  min-width: 180px !important;
  flex: 0 0 180px !important;
}

.message-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  border-radius: 0 28px 28px 0 !important;
}

.message-user {
  background: transparent !important;
}

.message-avatar {
  text-align: center !important;
  margin-bottom: 8px !important;
}

.message-avatar .avatar {
  border-radius: 50% !important;
  border: 2px solid rgba(60, 120, 60, 0.3) !important;
  transition: all 0.3s ease !important;
}

.message-avatar .avatar:hover {
  transform: scale(1.08) !important;
  border-color: rgba(60, 200, 60, 0.5) !important;
  box-shadow: 0 0 40px rgba(60,200,60,0.15) !important;
}

.message-userDetails {
  text-align: center !important;
}

.message-name {
  font-weight: 600 !important;
  font-size: 15px !important;
}

.message-name a {
  color: #c0e0c0 !important;
}

.message-name a:hover {
  color: #e0f8e0 !important;
  text-shadow: 0 0 20px rgba(80,200,80,0.15) !important;
}

.userBanner {
  background: rgba(60, 120, 60, 0.15) !important;
  border-radius: 40px !important;
  padding: 2px 14px !important;
  font-size: 11px !important;
  color: #a0c0a0 !important;
  display: inline-block !important;
  margin-top: 4px !important;
}

.userBanner--red {
  background: rgba(160, 60, 60, 0.2) !important;
  color: #cc8888 !important;
}

.userBanner--primary {
  background: rgba(60, 120, 60, 0.15) !important;
  color: #a0c0a0 !important;
}

.message-userExtras {
  margin-top: 8px !important;
  font-size: 12px !important;
  color: #80a080 !important;
}

.message-userExtras .pairs {
  padding: 2px 0 !important;
}

.message-userExtras .pairs dt {
  color: #709070 !important;
}

.message-userExtras .pairs dd {
  color: #a0c0a0 !important;
}

.message-attribution {
  background: rgba(20, 40, 25, 0.2) !important;
  padding: 8px 16px !important;
  border-bottom: 1px solid rgba(60,120,60,0.08) !important;
}

.message-attribution a {
  color: #80a080 !important;
}

.message-attribution a:hover {
  color: #b0d0b0 !important;
}

.message-newIndicator {
  background: rgba(60, 140, 60, 0.2) !important;
  color: #80d080 !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
}

.message-content {
  padding: 16px !important;
}

.message-body {
  color: #d0e0d0 !important;
  font-size: 15px !important;
  line-height: 1.7 !important;
}

.message-body .bbWrapper {
  color: #d0e0d0 !important;
}

.message-body a {
  color: #80d080 !important;
}

.message-body a:hover {
  color: #a0e8a0 !important;
  text-shadow: 0 0 20px rgba(80,200,80,0.15) !important;
}

.message-body .bbMediaWrapper {
  border-radius: 20px !important;
  overflow: hidden !important;
  background: rgba(20, 40, 25, 0.6) !important;
  border: 1px solid rgba(60,120,60,0.15) !important;
}

.message-body .bbMediaWrapper iframe {
  border-radius: 20px !important;
}

.message-fields--before {
  background: rgba(20, 40, 25, 0.3) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  margin-bottom: 12px !important;
  border: 1px solid rgba(60,120,60,0.08) !important;
}

.message-fields--before .pairs {
  padding: 2px 0 !important;
}

.message-fields--before .pairs dt {
  color: #709070 !important;
  font-weight: 500 !important;
}

.message-fields--before .pairs dd {
  color: #b0d0b0 !important;
}

.message-signature {
  background: rgba(20, 40, 25, 0.15) !important;
  border-top: 1px solid rgba(60,120,60,0.08) !important;
  padding: 12px 16px !important;
  margin-top: 12px !important;
  border-radius: 0 0 28px 28px !important;
  font-size: 13px !important;
  color: #80a080 !important;
  max-height: 100px !important;
  overflow: hidden !important;
  transition: max-height 0.3s ease !important;
}

.message-signature--expanded {
  max-height: 500px !important;
}

.message-signature .bbWrapper {
  color: #80a080 !important;
}

.message-signature a {
  color: #70a070 !important;
}

.message-signature a:hover {
  color: #90c090 !important;
}

.uix_signatureExpand {
  cursor: pointer !important;
  color: #709070 !important;
  font-size: 11px !important;
  text-align: center !important;
  padding: 4px !important;
  border-radius: 40px !important;
  background: rgba(60, 120, 60, 0.08) !important;
  margin-bottom: 6px !important;
  transition: all 0.2s !important;
}

.uix_signatureExpand:hover {
  background: rgba(60, 140, 60, 0.15) !important;
  color: #a0c0a0 !important;
}

.actionBar {
  background: rgba(20, 40, 25, 0.15) !important;
  border-top: 1px solid rgba(60,120,60,0.08) !important;
  padding: 6px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  border-radius: 0 0 28px 28px !important;
}

.actionBar-action {
  background: transparent !important;
  color: #80a080 !important;
  padding: 4px 12px !important;
  border-radius: 40px !important;
  font-size: 13px !important;
  transition: all 0.2s !important;
  cursor: pointer !important;
}

.actionBar-action:hover {
  background: rgba(60, 140, 60, 0.15) !important;
  color: #b0d0b0 !important;
}

.actionBar-action--reaction {
  background: rgba(60, 120, 60, 0.08) !important;
}

.actionBar-action--reaction:hover {
  background: rgba(60, 140, 60, 0.2) !important;
}

.actionBar-action--menuTrigger {
  color: #709070 !important;
}

.actionBar-action--menuTrigger:hover {
  background: rgba(60, 120, 60, 0.1) !important;
}

.blockStatus {
  background: rgba(25, 50, 30, 0.5) !important;
  border-radius: 40px !important;
  border: 1px solid rgba(60,120,60,0.15) !important;
  padding: 8px 24px !important;
  color: #b0d0b0 !important;
  backdrop-filter: blur(4px) !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 8px !important;
}

.blockStatus-message {
  color: #b0d0b0 !important;
}

.blockStatus-message--locked {
  border-color: #cc8888 !important;
  color: #cc8888 !important;
  background: rgba(160, 60, 60, 0.1) !important;
  border-radius: 40px !important;
  padding: 4px 16px !important;
}

.message-newIndicator,
.uix_newIndicator {
  background: rgba(60, 140, 60, 0.2) !important;
  color: #80d080 !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  font-weight: 600 !important;
}

.message--deleted {
  opacity: 0.5 !important;
  background: rgba(160, 60, 60, 0.1) !important;
  border-color: rgba(160, 60, 60, 0.15) !important;
}

.messageNotice--deleted {
  background: rgba(160, 60, 60, 0.08) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  color: #cc8888 !important;
}

.messageNotice--deleted a {
  color: #cc8888 !important;
}

.messageNotice--deleted a:hover {
  color: #e0a0a0 !important;
}

.reactionsBar {
  background: rgba(20, 40, 25, 0.2) !important;
  border-radius: 40px !important;
  padding: 4px 12px !important;
  margin: 0 16px 8px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 2px !important;
  min-height: 28px !important;
}

.reaction {
  background: rgba(60, 120, 60, 0.1) !important;
  border-radius: 40px !important;
  padding: 2px 8px !important;
  transition: all 0.2s !important;
}

.reaction:hover {
  background: rgba(60, 140, 60, 0.2) !important;
  transform: scale(1.05) !important;
}

.reaction-image--emoji {
  width: 20px !important;
  height: 20px !important;
  border-radius: 50% !important;
}

.reactionSummary {
  background: rgba(25, 50, 30, 0.3) !important;
  border-radius: 40px !important;
  padding: 2px 10px !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 2px !important;
  border: 1px solid rgba(60,120,60,0.1) !important;
}

.reactionSummary .reaction {
  padding: 1px 2px !important;
  background: transparent !important;
}

.reactionSummary .reaction:hover {
  transform: none !important;
  background: transparent !important;
}

.reactionSummary .reaction-image--emoji {
  width: 18px !important;
  height: 18px !important;
}

.pageNav {
  background: rgba(25, 50, 30, 0.5) !important;
  backdrop-filter: blur(4px) !important;
  border-radius: 40px !important;
  padding: 6px !important;
  border: 1px solid rgba(60,120,60,0.12) !important;
  display: inline-flex !important;
  flex-wrap: wrap !important;
  align-items: center !important;
  gap: 2px !important;
}

.pageNav a,
.pageNav .pageNav-page,
.pageNav-page,
.pageNav-page--current,
.pageNav-page--skip,
.pageNav-page--skipEnd,
.pageNav-page--later {
  display: inline-block !important;
  border-radius: 30px !important;
  padding: 6px 14px !important;
  min-width: 32px !important;
  height: 32px !important;
  line-height: 20px !important;
  text-align: center !important;
  background: transparent !important;
  color: #90b090 !important;
  font-size: 14px !important;
  font-weight: 500 !important;
  transition: all 0.2s ease !important;
  border: none !important;
  margin: 0 !important;
}

.pageNav a:hover,
.pageNav .pageNav-page:hover {
  background: rgba(60, 140, 60, 0.2) !important;
  color: #d0e8d0 !important;
  transform: scale(1.05) !important;
}

.pageNav .pageNav-page--current,
.pageNav-page--current {
  background: rgba(60, 140, 60, 0.25) !important;
  color: #c0e8c0 !important;
  box-shadow: 0 0 0 1px rgba(60,160,60,0.2) !important;
  font-weight: 700 !important;
}

.pageNav .pageNav-page--skip,
.pageNav-page--skip,
.pageNav .pageNav-page--skipEnd,
.pageNav-page--skipEnd,
.pageNav .pageNav-page--later,
.pageNav-page--later {
  color: #609060 !important;
  cursor: default !important;
}

.pageNav .pageNav-page--skip:hover,
.pageNav-page--skip:hover,
.pageNav .pageNav-page--skipEnd:hover,
.pageNav-page--skipEnd:hover,
.pageNav .pageNav-page--later:hover,
.pageNav-page--later:hover {
  background: transparent !important;
  transform: none !important;
  color: #609060 !important;
}

.pageNav .pageNav-jump {
  background: rgba(60, 120, 60, 0.1) !important;
  border-radius: 40px !important;
  color: #90b090 !important;
  padding: 6px 12px !important;
  border: none !important;
}

.pageNav .pageNav-jump:hover {
  background: rgba(60, 140, 60, 0.2) !important;
  color: #c0e0c0 !important;
}

.block-filterBar,
.filterBar {
  background: rgba(25, 50, 30, 0.3) !important;
  border-radius: 40px !important;
  padding: 8px 16px !important;
  border: 1px solid rgba(60,120,60,0.1) !important;
  display: flex !important;
  align-items: center !important;
  gap: 8px !important;
  margin-bottom: 12px !important;
}

.filterBar-menuTrigger {
  color: #90b090 !important;
  background: transparent !important;
  padding: 4px 12px !important;
  border-radius: 40px !important;
  transition: all 0.2s !important;
}

.filterBar-menuTrigger:hover {
  color: #c0e0c0 !important;
  background: rgba(60, 140, 60, 0.15) !important;
}

.p-breadcrumbs {
  background: transparent !important;
  padding: 8px 0 !important;
}

.p-breadcrumbs li {
  color: #80a080 !important;
}

.p-breadcrumbs a {
  color: #90b090 !important;
}

.p-breadcrumbs a:hover {
  color: #b0d0b0 !important;
  text-shadow: 0 0 20px rgba(80,200,80,0.1) !important;
}

.p-footer {
  background: rgba(20, 40, 25, 0.7) !important;
  backdrop-filter: blur(12px) !important;
  border-top: 1px solid rgba(60,120,60,0.15) !important;
  border-radius: 40px 40px 0 0 !important;
  padding: 24px !important;
  margin-top: 32px !important;
  box-shadow: 0 -4px 32px rgba(0,0,0,0.4) !important;
}

.p-footer-inner {
  background: transparent !important;
}

.p-footer-copyright {
  color: #709070 !important;
}

.p-footer-copyright a {
  color: #80a080 !important;
}

.p-footer-copyright a:hover {
  color: #a0c0a0 !important;
  text-shadow: 0 0 20px rgba(80,200,80,0.1) !important;
}

.p-footer-linkList a {
  color: #80a080 !important;
}

.p-footer-linkList a:hover {
  color: #b0d0b0 !important;
}

.button {
