(function() {
  const container = document.createElement('div');
  container.id = 'dark-forest-leaves';
  container.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:9999;overflow:hidden;';
  document.body.prepend(container);

  const svgLeaf = `
    <svg viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg">
      <path d="M50 5 C60 15 90 35 85 55 C80 75 60 90 50 95 C40 90 20 75 15 55 C10 35 40 15 50 5 Z" fill="currentColor"/>
      <path d="M50 15 L50 85 M35 40 L65 60 M30 55 L70 50" stroke="rgba(0,0,0,0.15)" stroke-width="1.5" fill="none"/>
    </svg>
  `;

  function createLeaf(x, y, size, rotation, color, duration, delay) {
    const wrapper = document.createElement('div');
    wrapper.style.cssText = `
      position: absolute;
      left: ${x}%;
      top: ${y}%;
      width: ${size}px;
      height: ${size}px;
      color: ${color};
      opacity: 0.6;
      transform: rotate(${rotation}deg);
      transform-origin: center;
      animation: leafSway ${duration}s ease-in-out ${delay}s infinite alternate;
      will-change: transform;
      filter: drop-shadow(0 4px 12px rgba(0,20,0,0.3));
      transition: transform 0.1s ease-out;
    `;
    wrapper.innerHTML = svgLeaf;
    wrapper.querySelector('svg').style.cssText = 'width:100%;height:100%;display:block;';
    return wrapper;
  }

  const leafColors = ['#2a5a2a', '#3a7a3a', '#4a8a4a', '#2a6a2a', '#5a9a5a', '#3a6a3a'];
  const positions = [
    { x: 2, y: 2, size: 45, rotation: 15, color: leafColors[0], duration: 12, delay: 0 },
    { x: 94, y: 3, size: 38, rotation: -25, color: leafColors[1], duration: 14, delay: 2 },
    { x: 3, y: 88, size: 40, rotation: 35, color: leafColors[2], duration: 13, delay: 4 },
    { x: 91, y: 85, size: 42, rotation: -15, color: leafColors[3], duration: 11, delay: 1 },
    { x: 50, y: 1, size: 32, rotation: 50, color: leafColors[4], duration: 15, delay: 3 },
    { x: 47, y: 94, size: 34, rotation: -35, color: leafColors[5], duration: 16, delay: 5 },
    { x: 8, y: 45, size: 28, rotation: 65, color: leafColors[0], duration: 13, delay: 2.5 },
    { x: 87, y: 42, size: 30, rotation: -50, color: leafColors[1], duration: 14, delay: 1.5 },
    { x: 2, y: 25, size: 25, rotation: 10, color: leafColors[2], duration: 12, delay: 3.5 },
    { x: 93, y: 68, size: 26, rotation: -20, color: leafColors[3], duration: 11, delay: 4.5 },
    { x: 20, y: 5, size: 22, rotation: 30, color: leafColors[4], duration: 13, delay: 1.8 },
    { x: 78, y: 92, size: 24, rotation: -40, color: leafColors[5], duration: 12, delay: 3.2 }
  ];

  const leafElements = [];
  positions.forEach((p, index) => {
    const leaf = createLeaf(p.x, p.y, p.size, p.rotation, p.color, p.duration, p.delay);
    leaf.dataset.index = index;
    container.appendChild(leaf);
    leafElements.push(leaf);
  });

  if (!document.getElementById('leaf-sway-styles')) {
    const style = document.createElement('style');
    style.id = 'leaf-sway-styles';
    style.textContent = `
      @keyframes leafSway {
        0% { transform: rotate(var(--rot-start, 0deg)) translate(0, 0); }
        25% { transform: rotate(calc(var(--rot-start, 0deg) + 10deg)) translate(8px, -5px); }
        50% { transform: rotate(calc(var(--rot-start, 0deg) - 8deg)) translate(-6px, 6px); }
        75% { transform: rotate(calc(var(--rot-start, 0deg) + 7deg)) translate(10px, -3px); }
        100% { transform: rotate(calc(var(--rot-start, 0deg) - 5deg)) translate(-5px, 8px); }
      }
    `;
    document.head.appendChild(style);
  }

  leafElements.forEach((el, i) => {
    const rot = positions[i].rotation;
    el.style.setProperty('--rot-start', rot + 'deg');
    el.style.animation = `leafSway ${positions[i].duration}s ease-in-out ${positions[i].delay}s infinite alternate`;
  });

  let mouseX = 0, mouseY = 0;
  document.addEventListener('mousemove', (e) => {
    mouseX = (e.clientX / window.innerWidth) * 100;
    mouseY = (e.clientY / window.innerHeight) * 100;
    leafElements.forEach((leaf, i) => {
      const dx = mouseX - positions[i].x;
      const dy = mouseY - positions[i].y;
      const dist = Math.sqrt(dx*dx + dy*dy);
      if (dist < 15) {
        const pushX = (dx / dist) * 12;
        const pushY = (dy / dist) * 12;
        leaf.style.transform = `translate(${pushX}px, ${pushY}px) rotate(${positions[i].rotation + (Math.random()-0.5)*25}deg)`;
        leaf.style.transition = 'transform 0.2s ease-out';
        leaf.style.opacity = '0.9';
      } else {
        leaf.style.transform = '';
        leaf.style.transition = 'transform 0.8s ease-out';
        leaf.style.opacity = '0.6';
      }
    });
  });

  console.log('[Dark Forest] Тема активирована с SVG-листьями');
})();
